import{_ as s,o as l,c as e,ag as i}from"./chunks/framework.CvgP6Fyv.js";const t="data:image/svg+xml,%3csvg%20xmlns='http://www.w3.org/2000/svg'%20viewBox='0%200%20200%20200'%3e%3cdefs%3e%3clinearGradient%20id='bg'%20x1='0%25'%20y1='0%25'%20x2='100%25'%20y2='100%25'%3e%3cstop%20offset='0%25'%20style='stop-color:%234f46e5'/%3e%3cstop%20offset='100%25'%20style='stop-color:%237c3aed'/%3e%3c/linearGradient%3e%3c/defs%3e%3ccircle%20cx='100'%20cy='100'%20r='100'%20fill='url(%23bg)'/%3e%3ccircle%20cx='100'%20cy='80'%20r='40'%20fill='white'%20opacity='0.9'/%3e%3cellipse%20cx='100'%20cy='170'%20rx='60'%20ry='50'%20fill='white'%20opacity='0.9'/%3e%3c/svg%3e",g=JSON.parse('{"title":"关于我","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1774792322000}'),r={name:"about.md"};function o(n,a,c,d,p,h){return l(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="关于我" tabindex="-1">关于我 <a class="header-anchor" href="#关于我" aria-label="Permalink to &quot;关于我&quot;">​</a></h1><div class="profile-header"><img src="'+t+'" alt="avatar" class="profile-avatar"><div class="profile-info"><h1>Qi Meng</h1><div class="title">凝聚态物理 | 博士研究生</div><div class="profile-links"><a href="mailto:qimeng0103@gmail.com">📧 Email</a><a href="https://github.com/qimeng0103" target="_blank">🐙 GitHub</a><a href="https://scholar.google.com" target="_blank">🎓 Google Scholar</a></div></div></div><h2 id="🔬-研究方向" tabindex="-1">🔬 研究方向 <a class="header-anchor" href="#🔬-研究方向" aria-label="Permalink to &quot;🔬 研究方向&quot;">​</a></h2><p>我的研究兴趣主要集中在凝聚态物理的理论与计算方向，特别是：</p><div class="research-areas"><div class="research-card"><h4>拓扑物态</h4><p>拓扑绝缘体、拓扑超导体、Weyl半金属等新型量子材料的理论研究</p></div><div class="research-card"><h4>量子输运</h4><p>利用非平衡格林函数和散射矩阵方法研究介观系统的电子输运性质</p></div><div class="research-card"><h4>强关联系统</h4><p>量子多体系统的数值模拟，包括DMRG、量子蒙特卡洛等方法</p></div><div class="research-card"><h4>量子计算</h4><p>量子算法设计、量子纠错以及量子模拟的理论研究</p></div></div><h2 id="💻-技术工具" tabindex="-1">💻 技术工具 <a class="header-anchor" href="#💻-技术工具" aria-label="Permalink to &quot;💻 技术工具&quot;">​</a></h2><p>在日常研究工作中，我主要使用以下工具和语言：</p><div class="skills-grid"><div class="skill-item"><span class="skill-icon">🐍</span><span class="skill-name">Python</span></div><div class="skill-item"><span class="skill-icon">🔷</span><span class="skill-name">Julia</span></div><div class="skill-item"><span class="skill-icon">📊</span><span class="skill-name">MATLAB</span></div><div class="skill-item"><span class="skill-icon">⚛️</span><span class="skill-name">Kwant</span></div><div class="skill-item"><span class="skill-icon">🔗</span><span class="skill-name">ITensor</span></div><div class="skill-item"><span class="skill-icon">🌊</span><span class="skill-name">Quantum ESPRESSO</span></div></div><h2 id="📝-关于本博客" tabindex="-1">📝 关于本博客 <a class="header-anchor" href="#📝-关于本博客" aria-label="Permalink to &quot;📝 关于本博客&quot;">​</a></h2><p>这个博客是我记录学习和研究过程的地方。内容包括：</p><ul><li><strong>研究笔记</strong> — 对物理概念的理解和推导</li><li><strong>计算教程</strong> — 数值方法和软件使用的经验分享</li><li><strong>文献解读</strong> — 经典论文和重要进展的阅读笔记</li><li><strong>技术随笔</strong> — 编程技巧和工作效率的提升</li></ul><h2 id="📮-联系方式" tabindex="-1">📮 联系方式 <a class="header-anchor" href="#📮-联系方式" aria-label="Permalink to &quot;📮 联系方式&quot;">​</a></h2><p>如果你对我的研究感兴趣，或有任何问题想要交流，欢迎通过以下方式联系我：</p><ul><li><strong>Email</strong>: <a href="mailto:qimeng0103@gmail.com" target="_blank" rel="noreferrer">qimeng0103@gmail.com</a></li><li><strong>GitHub</strong>: <a href="https://github.com/qimeng0103" target="_blank" rel="noreferrer">@qimeng0103</a></li></ul><hr><blockquote><p><em>&quot;The first principle is that you must not fool yourself — and you are the easiest person to fool.&quot;</em></p><p>— Richard Feynman</p></blockquote>',16)])])}const v=s(r,[["render",o]]);export{g as __pageData,v as default};
